import React, { useState, useRef, useEffect, useCallback } from "react";

const LOGO_SRC = "data:image/png;base64,";

const THEMES = [
  { id: "royal", name: "Royal Blue", from: "#0b1467", via: "#1b2fa8", to: "#3349d6", accent: "#ff5a3c", chip: "#ff5a3c" },
  { id: "wine", name: "Wine", from: "#3a0519", via: "#6b0f2b", to: "#9c1b3f", accent: "#ffd23f", chip: "#ffd23f" },
  { id: "forest", name: "Forest", from: "#06281c", via: "#0b4a32", to: "#127449", accent: "#ffce45", chip: "#ffce45" },
  { id: "purple", name: "Purple Reign", from: "#1a0a33", via: "#3b1170", to: "#5c1fa6", accent: "#ffb648", chip: "#ffb648" },
  { id: "sunset", name: "Sunset", from: "#3a0f12", via: "#7a1f1f", to: "#c2410c", accent: "#ffe066", chip: "#ffe066" },
  { id: "gold", name: "Black & Gold", from: "#0a0a0a", via: "#1c1c1c", to: "#2e2e2e", accent: "#e8b923", chip: "#e8b923" },
];

const FORMATS = {
  portrait: { w: 1080, h: 1080, label: "Social Media (Square)" },
  landscape: { w: 1920, h: 1080, label: "TV Screen (Landscape)" },
};

const DEFAULT_MESSAGE = `"May this new year of your life be filled with God's grace, peace, and abundant blessings. Amen."`;

function hexToRgb(hex) {
  const v = hex.replace("#", "");
  const num = parseInt(v, 16);
  return { r: (num >> 16) & 255, g: (num >> 8) & 255, b: num & 255 };
}

function loadImage(src) {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => resolve(img);
    img.onerror = reject;
    img.src = src;
  });
}

function loadFont() {
  if (document.getElementById("poppins-font-link")) return;
  const link = document.createElement("link");
  link.id = "poppins-font-link";
  link.rel = "stylesheet";
  link.href = "https://fonts.googleapis.com/css2?family=Poppins:ital,wght@0,400;0,500;0,600;0,700;0,800;0,900;1,600;1,700&display=swap";
  document.head.appendChild(link);
}

// ---------- Confetti generation (deterministic-ish, seeded per render) ----------
function makeConfetti(count, seedOffset, w, h) {
  const shapes = ["rect", "circle", "triangle"];
  const items = [];
  let seed = seedOffset * 999331 + 12345;
  const rand = () => {
    seed = (seed * 16807) % 2147483647;
    return (seed - 1) / 2147483646;
  };
  for (let i = 0; i < count; i++) {
    items.push({
      x: rand() * w,
      y: rand() * h,
      size: 6 + rand() * 16,
      rot: rand() * 360,
      shape: shapes[Math.floor(rand() * shapes.length)],
      colorIdx: Math.floor(rand() * 5),
    });
  }
  return items;
}

const CONFETTI_COLORS = ["#ff5a3c", "#3dd6c2", "#ffd23f", "#ff6fb5", "#7c5cff"];

function drawConfettiPiece(ctx, item) {
  ctx.save();
  ctx.translate(item.x, item.y);
  ctx.rotate((item.rot * Math.PI) / 180);
  ctx.fillStyle = CONFETTI_COLORS[item.colorIdx];
  const s = item.size;
  if (item.shape === "rect") {
    ctx.fillRect(-s / 2, -s / 4, s, s / 2);
  } else if (item.shape === "circle") {
    ctx.beginPath();
    ctx.arc(0, 0, s / 2.5, 0, Math.PI * 2);
    ctx.fill();
  } else {
    ctx.beginPath();
    ctx.moveTo(0, -s / 2);
    ctx.lineTo(s / 2, s / 2);
    ctx.lineTo(-s / 2, s / 2);
    ctx.closePath();
    ctx.fill();
  }
  ctx.restore();
}

function roundRectPath(ctx, x, y, w, h, r) {
  const rr = Math.min(r, w / 2, h / 2);
  ctx.beginPath();
  ctx.moveTo(x + rr, y);
  ctx.arcTo(x + w, y, x + w, y + h, rr);
  ctx.arcTo(x + w, y + h, x, y + h, rr);
  ctx.arcTo(x, y + h, x, y, rr);
  ctx.arcTo(x, y, x + w, y, rr);
  ctx.closePath();
}

function wrapText(ctx, text, maxWidth) {
  const words = text.split(" ");
  const lines = [];
  let current = "";
  for (const word of words) {
    const test = current ? current + " " + word : word;
    if (ctx.measureText(test).width > maxWidth && current) {
      lines.push(current);
      current = word;
    } else {
      current = test;
    }
  }
  if (current) lines.push(current);
  return lines;
}

// ---------- Main draw function ----------
async function drawFlyer(canvas, opts) {
  const { format, theme, name, dateText, message, photoImg, photoTransform, igHandle } = opts;
  const { w, h } = FORMATS[format];
  canvas.width = w;
  canvas.height = h;
  const ctx = canvas.getContext("2d");

  // Background gradient
  const grad = ctx.createLinearGradient(0, 0, w, h);
  grad.addColorStop(0, theme.from);
  grad.addColorStop(0.5, theme.via);
  grad.addColorStop(1, theme.to);
  ctx.fillStyle = grad;
  ctx.fillRect(0, 0, w, h);

  // subtle vignette
  const vg = ctx.createRadialGradient(w * 0.3, h * 0.3, w * 0.1, w * 0.5, h * 0.5, w * 0.8);
  vg.addColorStop(0, "rgba(255,255,255,0.06)");
  vg.addColorStop(1, "rgba(0,0,0,0.25)");
  ctx.fillStyle = vg;
  ctx.fillRect(0, 0, w, h);

  const isPortrait = format === "portrait";
  const pad = isPortrait ? w * 0.065 : w * 0.045;

  // ---- Confetti scattered around the right/edges (drawn before card so card sits on top) ----
  const confettiCount = isPortrait ? 38 : 46;
  const confetti = makeConfetti(confettiCount, 7, w, h);
  confetti.forEach((c) => {
    // keep confetti mostly out of the central text/photo zone by biasing toward edges
    drawConfettiPiece(ctx, c);
  });

  // ---- Header: logo + church name (left), instagram handle (right) ----
  const logoSize = isPortrait ? w * 0.11 : h * 0.15;
  const headerY = pad;
  try {
    if (opts.logoImg) {
      ctx.save();
      ctx.beginPath();
      ctx.arc(pad + logoSize / 2, headerY + logoSize / 2, logoSize / 2, 0, Math.PI * 2);
      ctx.closePath();
      ctx.clip();
      ctx.drawImage(opts.logoImg, pad, headerY, logoSize, logoSize);
      ctx.restore();
    }
  } catch (e) {}

  ctx.fillStyle = "#ffffff";
  ctx.textBaseline = "top";
  const churchFontSize = isPortrait ? w * 0.027 : h * 0.033;
  ctx.font = `700 ${churchFontSize}px Poppins, sans-serif`;
  const churchTextX = pad + logoSize + pad * 0.45;
  const churchLine1 = "CHRIST APOSTOLIC CHURCH";
  const churchLine2 = "HALLELUJAH DISTRICT HQ";
  const churchLineGap = churchFontSize * 1.25;
  const churchBlockHeight = churchFontSize + churchLineGap;
  const churchTextStartY = headerY + (logoSize - churchBlockHeight) / 2;
  ctx.fillText(churchLine1, churchTextX, churchTextStartY);
  ctx.fillText(churchLine2, churchTextX, churchTextStartY + churchLineGap);

  if (igHandle) {
    ctx.font = `600 ${churchFontSize * 0.9}px Poppins, sans-serif`;
    ctx.textAlign = "right";
    // small IG glyph (simple rounded square outline + dot)
    const igText = igHandle.startsWith("@") ? igHandle : "@" + igHandle;
    const igTextWidth = ctx.measureText(igText).width;
    const iconSize = churchFontSize * 1.1;
    const totalW = iconSize + 10 + igTextWidth;
    const rightX = w - pad;
    const iconX = rightX - totalW;
    const iconY = headerY + (logoSize - iconSize) / 2;
    ctx.save();
    ctx.strokeStyle = "#ffffff";
    ctx.lineWidth = Math.max(2, iconSize * 0.08);
    roundRectPath(ctx, iconX, iconY, iconSize, iconSize, iconSize * 0.28);
    ctx.stroke();
    ctx.beginPath();
    ctx.arc(iconX + iconSize / 2, iconY + iconSize / 2, iconSize * 0.22, 0, Math.PI * 2);
    ctx.stroke();
    ctx.beginPath();
    ctx.arc(iconX + iconSize * 0.78, iconY + iconSize * 0.22, iconSize * 0.05, 0, Math.PI * 2);
    ctx.fillStyle = "#ffffff";
    ctx.fill();
    ctx.restore();
    ctx.textAlign = "left";
    ctx.fillStyle = "#ffffff";
    ctx.fillText(igText, iconX + iconSize + 10, iconY + iconSize * 0.07);
  }

  // ---- Layout regions ----
  let cardX, cardY, cardW, cardH, textX, textRightEdge, textTop;
  const contentTop = headerY + logoSize + pad * 0.9;

  if (isPortrait) {
    cardW = w * 0.42;
    cardH = h * 0.58;
    cardX = pad;
    const availableH = h - contentTop - pad * 1.6;
    cardY = contentTop + Math.max(0, (availableH - cardH) / 2);
    textX = cardX + cardW + pad * 0.7;
    textRightEdge = w - pad;
    textTop = cardY;
  } else {
    cardW = w * 0.24;
    cardH = h * 0.72;
    cardX = w - pad - cardW;
    cardY = contentTop - h * 0.01;
    textX = pad;
    textRightEdge = cardX - pad * 0.8;
    textTop = cardY;
  }

  // ---- Photo card (white rounded frame with red inner photo area) ----
  const frameRadius = cardW * 0.09;
  ctx.save();
  ctx.shadowColor = "rgba(0,0,0,0.35)";
  ctx.shadowBlur = cardW * 0.05;
  ctx.shadowOffsetY = cardW * 0.02;
  ctx.fillStyle = "#ffffff";
  roundRectPath(ctx, cardX, cardY, cardW, cardH, frameRadius);
  ctx.fill();
  ctx.restore();

  const innerPad = cardW * 0.065;
  const nameStripH = cardH * 0.135;
  const photoX = cardX + innerPad;
  const photoY = cardY + innerPad;
  const photoW = cardW - innerPad * 2;
  const photoH = cardH - innerPad * 2 - nameStripH;
  const photoRadius = frameRadius * 0.55;

  roundRectPath(ctx, photoX, photoY, photoW, photoH, photoRadius);
  if (photoImg && photoImg.complete && photoImg.naturalWidth) {
    ctx.save();
    ctx.clip();
    const iw = photoImg.naturalWidth;
    const ih = photoImg.naturalHeight;
    const scale = photoTransform?.scale || 1;
    const offX = photoTransform?.offsetX || 0;
    const offY = photoTransform?.offsetY || 0;

    const coverScale = Math.max(photoW / iw, photoH / ih) * scale;
    const drawW = iw * coverScale;
    const drawH = ih * coverScale;
    const dx = photoX + (photoW - drawW) / 2 + offX;
    const dy = photoY + (photoH - drawH) / 2 + offY;
    ctx.drawImage(photoImg, dx, dy, drawW, drawH);
    ctx.restore();
  } else {
    ctx.fillStyle = "#ef4136";
    ctx.fill();
    ctx.save();
    ctx.clip();
    ctx.fillStyle = "rgba(255,255,255,0.85)";
    ctx.font = `600 ${photoW * 0.09}px Poppins, sans-serif`;
    ctx.textAlign = "center";
    ctx.save();
    ctx.translate(photoX + photoW / 2, photoY + photoH / 2);
    ctx.rotate(-0.12);
    ctx.fillText("Image here", 0, 0);
    ctx.restore();
    ctx.restore();
    ctx.textAlign = "left";
  }

  // name strip
  const stripY = photoY + photoH + innerPad * 0.5;
  ctx.fillStyle = "#0f172a";
  const nameFontSize = Math.min(cardW * 0.105, nameStripH * 0.62);
  ctx.font = `600 ${nameFontSize}px Poppins, sans-serif`;
  ctx.textAlign = "left";
  ctx.textBaseline = "middle";
  let displayName = name || "Name here";
  // shrink to fit
  let fSize = nameFontSize;
  ctx.font = `600 ${fSize}px Poppins, sans-serif`;
  while (ctx.measureText(displayName).width > photoW - 4 && fSize > 10) {
    fSize -= 2;
    ctx.font = `600 ${fSize}px Poppins, sans-serif`;
  }
  ctx.fillText(displayName, photoX + 2, stripY + nameStripH / 2);
  ctx.textBaseline = "alphabetic";

  // ---- Headline "Happy Birthday" ----
  ctx.textAlign = "left";
  ctx.fillStyle = "#ffffff";
  let headlineSize = isPortrait ? w * 0.092 : h * 0.155;
  const headlineMaxWidth = textRightEdge - textX;
  ctx.font = `800 ${headlineSize}px Poppins, sans-serif`;
  // shrink to fit the wider of the two words within the available width
  while (
    (ctx.measureText("Happy").width > headlineMaxWidth ||
      ctx.measureText("Birthday").width > headlineMaxWidth) &&
    headlineSize > 10
  ) {
    headlineSize -= 1;
    ctx.font = `800 ${headlineSize}px Poppins, sans-serif`;
  }
  let hy = textTop + headlineSize * 0.95;
  ctx.fillText("Happy", textX, hy);
  hy += headlineSize * 1.0;
  ctx.fillText("Birthday", textX, hy);

  // ---- Message ----
  const msgSize = isPortrait ? w * 0.026 : h * 0.034;
  ctx.font = `italic 500 ${msgSize}px Poppins, sans-serif`;
  ctx.fillStyle = "rgba(255,255,255,0.92)";
  const maxTextWidth = textRightEdge - textX;
  const lines = wrapText(ctx, message || DEFAULT_MESSAGE, maxTextWidth);
  let my = hy + headlineSize * 0.28;
  const lineH = msgSize * 1.38;
  lines.forEach((line) => {
    my += lineH;
    ctx.fillText(line, textX, my);
  });

  // ---- Date chip ----
  const chipY = my + lineH * 0.7;
  const chipH = isPortrait ? h * 0.05 : h * 0.08;
  const chipPaddingX = chipH * 0.5;
  ctx.font = `600 ${chipH * 0.42}px Poppins, sans-serif`;
  const dateDisplay = dateText || "Date here";
  const chipTextW = ctx.measureText(dateDisplay).width;
  let chipW = chipTextW + chipPaddingX * 2;
  chipW = Math.min(chipW, maxTextWidth);
  ctx.save();
  ctx.shadowColor = "rgba(0,0,0,0.25)";
  ctx.shadowBlur = chipH * 0.15;
  ctx.fillStyle = "#ffffff";
  roundRectPath(ctx, textX, chipY, chipW, chipH, chipH * 0.28);
  ctx.fill();
  ctx.restore();
  ctx.fillStyle = "#0f172a";
  ctx.textBaseline = "middle";
  ctx.fillText(dateDisplay, textX + chipPaddingX, chipY + chipH / 2 + chipH * 0.02);
  ctx.textBaseline = "alphabetic";

}

// ---------------- Photo cropper sub-component ----------------
function PhotoCropper({ imgSrc, transform, onChange }) {
  const wrapRef = useRef(null);
  const dragState = useRef(null);

  const onPointerDown = (e) => {
    dragState.current = {
      startX: e.clientX,
      startY: e.clientY,
      offsetX: transform.offsetX,
      offsetY: transform.offsetY,
    };
    e.currentTarget.setPointerCapture(e.pointerId);
  };
  const onPointerMove = (e) => {
    if (!dragState.current) return;
    const dx = e.clientX - dragState.current.startX;
    const dy = e.clientY - dragState.current.startY;
    onChange({ ...transform, offsetX: dragState.current.offsetX + dx, offsetY: dragState.current.offsetY + dy });
  };
  const onPointerUp = () => {
    dragState.current = null;
  };

  return (
    <div className="space-y-2">
      <div
        ref={wrapRef}
        onPointerDown={onPointerDown}
        onPointerMove={onPointerMove}
        onPointerUp={onPointerUp}
        onPointerLeave={onPointerUp}
        className="relative w-full aspect-[3/4] overflow-hidden rounded-2xl border-2 border-slate-200 bg-slate-100 cursor-move select-none touch-none"
        style={{ maxWidth: 220 }}
      >
        <img
          src={imgSrc}
          alt="crop preview"
          draggable={false}
          className="absolute top-1/2 left-1/2 max-w-none pointer-events-none"
          style={{
            transform: `translate(-50%, -50%) translate(${transform.offsetX}px, ${transform.offsetY}px) scale(${transform.scale})`,
            width: "100%",
            height: "100%",
            objectFit: "cover",
          }}
        />
      </div>
      <div className="flex items-center gap-2" style={{ maxWidth: 220 }}>
        <span className="text-xs text-slate-500 w-10">Zoom</span>
        <input
          type="range"
          min="1"
          max="3"
          step="0.01"
          value={transform.scale}
          onChange={(e) => onChange({ ...transform, scale: parseFloat(e.target.value) })}
          className="flex-1 accent-indigo-600"
        />
      </div>
      <p className="text-xs text-slate-400" style={{ maxWidth: 220 }}>Drag photo to reposition</p>
    </div>
  );
}

// ---------------- Main App ----------------
export default function BirthdayFlyerMaker() {
  const canvasRef = useRef(null);
  const [format, setFormat] = useState("portrait");
  const [themeId, setThemeId] = useState("royal");
  const [customColor, setCustomColor] = useState(null);
  const [name, setName] = useState("");
  const [dateText, setDateText] = useState("");
  const [message, setMessage] = useState(DEFAULT_MESSAGE);
  const igHandle = "cacisegunhalleluyah"; // fixed — church publicity handle, not editable
  const [photoSrc, setPhotoSrc] = useState(null);
  const [photoTransform, setPhotoTransform] = useState({ scale: 1, offsetX: 0, offsetY: 0 });
  const [logoImg, setLogoImg] = useState(null);
  const [photoImgEl, setPhotoImgEl] = useState(null);
  const [rendering, setRendering] = useState(false);
  const [showCustomPicker, setShowCustomPicker] = useState(false);
  const fileInputRef = useRef(null);

  useEffect(() => {
    loadFont();
    loadImage(LOGO_SRC).then(setLogoImg).catch(() => setLogoImg(null));
  }, []);

  useEffect(() => {
    if (!photoSrc) {
      setPhotoImgEl(null);
      return;
    }
    loadImage(photoSrc).then(setPhotoImgEl).catch(() => setPhotoImgEl(null));
  }, [photoSrc]);

  const activeTheme = customColor
    ? { ...customColor }
    : THEMES.find((t) => t.id === themeId) || THEMES[0];

  const render = useCallback(async () => {
    if (!canvasRef.current || !logoImg) return;
    setRendering(true);
    await drawFlyer(canvasRef.current, {
      format,
      theme: activeTheme,
      name,
      dateText,
      message,
      photoImg: photoImgEl,
      photoTransform,
      logoImg,
      igHandle,
    });
    setRendering(false);
  }, [format, activeTheme, name, dateText, message, photoImgEl, photoTransform, logoImg, igHandle]);

  useEffect(() => {
    render();
  }, [render]);

  const handlePhotoUpload = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      setPhotoSrc(ev.target.result);
      setPhotoTransform({ scale: 1, offsetX: 0, offsetY: 0 });
    };
    reader.readAsDataURL(file);
  };

  const handleDownload = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const link = document.createElement("a");
    const fname = `birthday-${(name || "celebrant").toLowerCase().replace(/\s+/g, "-")}-${format}.png`;
    link.download = fname;
    link.href = canvas.toDataURL("image/png");
    link.click();
  };

  function makeCustomFromHex(hex) {
    const { r, g, b } = hexToRgb(hex);
    const darken = (f) => `rgb(${Math.round(r * f)}, ${Math.round(g * f)}, ${Math.round(b * f)})`;
    return {
      id: "custom",
      name: "Custom",
      from: darken(0.45),
      via: hex,
      to: darken(1.25 > 255 ? 1 : 1.2),
      accent: "#ffd23f",
      chip: "#ffd23f",
    };
  }

  return (
    <div className="min-h-screen w-full bg-slate-50" style={{ fontFamily: "Poppins, sans-serif" }}>
      <div className="max-w-6xl mx-auto px-4 py-6 md:py-10">
        <header className="mb-6 md:mb-8">
          <div className="flex items-center gap-3">
            {logoImg && <img src={LOGO_SRC} alt="logo" className="w-10 h-10 md:w-12 md:h-12 object-contain" />}
            <div>
              <h1 className="text-xl md:text-2xl font-extrabold text-slate-900 tracking-tight">Birthday Flyer Maker</h1>
              <p className="text-xs md:text-sm text-slate-500 font-medium">Christ Apostolic Church — Hallelujah District HQ</p>
            </div>
          </div>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-[380px_1fr] gap-6 md:gap-8">
          {/* Controls */}
          <div className="space-y-5 order-2 lg:order-1">
            <section className="bg-white rounded-2xl p-4 md:p-5 shadow-sm border border-slate-100">
              <h2 className="text-sm font-bold text-slate-800 mb-3 uppercase tracking-wide">Format</h2>
              <div className="grid grid-cols-2 gap-2">
                {Object.entries(FORMATS).map(([key, f]) => (
                  <button
                    key={key}
                    onClick={() => setFormat(key)}
                    className={`px-3 py-2.5 rounded-xl text-sm font-semibold border-2 transition-all ${
                      format === key
                        ? "border-indigo-600 bg-indigo-50 text-indigo-700"
                        : "border-slate-200 text-slate-600 hover:border-slate-300"
                    }`}
                  >
                    {f.label}
                  </button>
                ))}
              </div>
            </section>

            <section className="bg-white rounded-2xl p-4 md:p-5 shadow-sm border border-slate-100">
              <h2 className="text-sm font-bold text-slate-800 mb-3 uppercase tracking-wide">Celebrant Photo</h2>
              <input
                ref={fileInputRef}
                type="file"
                accept="image/*"
                onChange={handlePhotoUpload}
                className="hidden"
              />
              {!photoSrc ? (
                <button
                  onClick={() => fileInputRef.current?.click()}
                  className="w-full py-8 rounded-xl border-2 border-dashed border-slate-300 text-slate-500 hover:border-indigo-400 hover:text-indigo-600 transition-colors flex flex-col items-center gap-2"
                >
                  <span className="text-3xl">📷</span>
                  <span className="text-sm font-medium">Tap to upload photo</span>
                </button>
              ) : (
                <div className="space-y-3">
                  <PhotoCropper imgSrc={photoSrc} transform={photoTransform} onChange={setPhotoTransform} />
                  <button
                    onClick={() => fileInputRef.current?.click()}
                    className="text-sm font-semibold text-indigo-600 hover:text-indigo-700"
                  >
                    Choose a different photo
                  </button>
                </div>
              )}
            </section>

            <section className="bg-white rounded-2xl p-4 md:p-5 shadow-sm border border-slate-100">
              <h2 className="text-sm font-bold text-slate-800 mb-3 uppercase tracking-wide">Details</h2>
              <div className="space-y-3">
                <div>
                  <label className="text-xs font-semibold text-slate-500 mb-1 block">Celebrant's name</label>
                  <input
                    type="text"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    placeholder="e.g. Deaconess Folake Adeyemi"
                    className="w-full px-3 py-2.5 rounded-xl border border-slate-200 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                  />
                </div>
                <div>
                  <label className="text-xs font-semibold text-slate-500 mb-1 block">Date</label>
                  <input
                    type="text"
                    value={dateText}
                    onChange={(e) => setDateText(e.target.value)}
                    placeholder="e.g. June 22"
                    className="w-full px-3 py-2.5 rounded-xl border border-slate-200 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                  />
                </div>
                <div>
                  <label className="text-xs font-semibold text-slate-500 mb-1 block">Message</label>
                  <textarea
                    value={message}
                    onChange={(e) => setMessage(e.target.value)}
                    rows={3}
                    className="w-full px-3 py-2.5 rounded-xl border border-slate-200 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent resize-none"
                  />
                </div>
              </div>
            </section>

            <section className="bg-white rounded-2xl p-4 md:p-5 shadow-sm border border-slate-100">
              <h2 className="text-sm font-bold text-slate-800 mb-3 uppercase tracking-wide">Background Color</h2>
              <div className="grid grid-cols-3 gap-2 mb-3">
                {THEMES.map((t) => (
                  <button
                    key={t.id}
                    onClick={() => {
                      setThemeId(t.id);
                      setCustomColor(null);
                    }}
                    className={`relative rounded-xl overflow-hidden h-14 border-2 transition-all ${
                      !customColor && themeId === t.id ? "border-indigo-600 ring-2 ring-indigo-200" : "border-transparent"
                    }`}
                    style={{ background: `linear-gradient(135deg, ${t.from}, ${t.to})` }}
                    title={t.name}
                  >
                    {!customColor && themeId === t.id && (
                      <span className="absolute inset-0 flex items-center justify-center text-white text-lg">✓</span>
                    )}
                  </button>
                ))}
              </div>
              <button
                onClick={() => setShowCustomPicker((s) => !s)}
                className={`w-full px-3 py-2.5 rounded-xl text-sm font-semibold border-2 transition-all ${
                  customColor ? "border-indigo-600 bg-indigo-50 text-indigo-700" : "border-slate-200 text-slate-600 hover:border-slate-300"
                }`}
              >
                {customColor ? "Custom color selected ✓" : "Pick a custom color"}
              </button>
              {showCustomPicker && (
                <div className="mt-3 flex items-center gap-3">
                  <input
                    type="color"
                    defaultValue="#1b2fa8"
                    onChange={(e) => setCustomColor(makeCustomFromHex(e.target.value))}
                    className="w-12 h-12 rounded-lg cursor-pointer border border-slate-200"
                  />
                  <span className="text-xs text-slate-500">Choose any color for the background</span>
                </div>
              )}
            </section>
          </div>

          {/* Preview */}
          <div className="order-1 lg:order-2">
            <div className="bg-white rounded-2xl p-4 md:p-6 shadow-sm border border-slate-100 lg:sticky lg:top-6">
              <div className="flex items-center justify-between mb-4">
                <h2 className="text-sm font-bold text-slate-800 uppercase tracking-wide">Preview</h2>
                {rendering && <span className="text-xs text-slate-400">Rendering…</span>}
              </div>
              <div className="rounded-xl overflow-hidden border border-slate-200 bg-slate-100 flex items-center justify-center">
                <canvas
                  ref={canvasRef}
                  className="w-full h-auto block"
                  style={{ maxHeight: "70vh", objectFit: "contain" }}
                />
              </div>
              <button
                onClick={handleDownload}
                className="mt-4 w-full py-3.5 rounded-xl bg-indigo-600 hover:bg-indigo-700 text-white font-bold text-sm transition-colors shadow-sm flex items-center justify-center gap-2"
              >
                <span>⬇</span> Download Image
              </button>
              <p className="text-center text-xs text-slate-400 mt-2">
                Download, then share to Instagram, WhatsApp, or Facebook
              </p>
            </div>
          </div>
        </div>

        <footer className="mt-10 pb-4 text-center">
          <p className="text-xs text-slate-400">Made with ♥ for Christ Apostolic Church, Hallelujah District HQ</p>
          <p className="text-xs text-slate-300 mt-1">Designed by Timi Graphics</p>
        </footer>
      </div>
    </div>
  );
}
